package main

import (
    "encoding/json"
    "fmt"
    "io"
    "net/http"
)

// ---- Request/Response structs ----
type Player struct {
    Name   string `json:"name"`
    Health int    `json:"health"`
    Attack int    `json:"attack"`
    Level  int    `json:"level"`
}

type CreatePlayerRequest struct {
    Name   string `json:"name"`
    Health int    `json:"health,omitempty"`
    Attack int    `json:"attack,omitempty"`
}

type Response struct {
    Success bool        `json:"success"`
    Message string      `json:"message"`
    Data    interface{} `json:"data,omitempty"`
}

func main() {
    // ---- JSON response ----
    http.HandleFunc("/api/players", func(w http.ResponseWriter, r *http.Request) {
        switch r.Method {
        case "GET":
            players := []Player{
                {Name: "Hero", Health: 100, Attack: 20, Level: 5},
                {Name: "Aragorn", Health: 120, Attack: 25, Level: 8},
                {Name: "Gandalf", Health: 80, Attack: 15, Level: 6},
            }

            w.Header().Set("Content-Type", "application/json")
            w.WriteHeader(http.StatusOK)
            json.NewEncoder(w).Encode(Response{
                Success: true,
                Message: "Players retrieved successfully",
                Data:    players,
            })

        case "POST":
            // ---- Read JSON request ----
            body, err := io.ReadAll(r.Body)
            if err != nil {
                http.Error(w, "Failed to read body", http.StatusBadRequest)
                return
            }
            defer r.Body.Close()

            var req CreatePlayerRequest
            err = json.Unmarshal(body, &req)
            if err != nil {
                w.Header().Set("Content-Type", "application/json")
                w.WriteHeader(http.StatusBadRequest)
                json.NewEncoder(w).Encode(Response{
                    Success: false,
                    Message: "Invalid JSON: " + err.Error(),
                })
                return
            }

            // ---- Validate ----
            if req.Name == "" {
                w.Header().Set("Content-Type", "application/json")
                w.WriteHeader(http.StatusBadRequest)
                json.NewEncoder(w).Encode(Response{
                    Success: false,
                    Message: "Name is required",
                })
                return
            }

            // ---- Create player ----
            player := Player{
                Name:   req.Name,
                Health: req.Health,
                Attack: req.Attack,
                Level:  1,
            }

            if player.Health == 0 {
                player.Health = 100
            }
            if player.Attack == 0 {
                player.Attack = 10
            }

            w.Header().Set("Content-Type", "application/json")
            w.WriteHeader(http.StatusCreated)
            json.NewEncoder(w).Encode(Response{
                Success: true,
                Message: "Player created successfully",
                Data:    player,
            })

        default:
            w.Header().Set("Content-Type", "application/json")
            w.WriteHeader(http.StatusMethodNotAllowed)
            json.NewEncoder(w).Encode(Response{
                Success: false,
                Message: "Method not allowed",
            })
        }
    })

    fmt.Println("Server starting on :8080")
    fmt.Println("Routes:")
    fmt.Println("  GET  /api/players")
    fmt.Println("  POST /api/players")

    http.ListenAndServe(":8080", nil)
}

