package main

import (
    "encoding/json"
    "fmt"
    "net/http"
)

type Item struct {
    Name  string `json:"name"`
    Value int    `json:"value"`
}

type Response struct {
    Success bool        `json:"success"`
    Message string      `json:"message"`
    Data    interface{} `json:"data,omitempty"`
}

func main() {
    http.HandleFunc("/api/items", func(w http.ResponseWriter, r *http.Request) {
        if r.Method != "POST" {
            w.Header().Set("Content-Type", "application/json")
            w.WriteHeader(http.StatusMethodNotAllowed)
            json.NewEncoder(w).Encode(Response{Success: false, Message: "Method not allowed"})
            return
        }

        var item Item
        err := json.NewDecoder(r.Body).Decode(&item)
        if err != nil {
            w.Header().Set("Content-Type", "application/json")
            w.WriteHeader(http.StatusBadRequest)
            json.NewEncoder(w).Encode(Response{Success: false, Message: "Invalid JSON"})
            return
        }

        if item.Name == "" {
            w.Header().Set("Content-Type", "application/json")
            w.WriteHeader(http.StatusBadRequest)
            json.NewEncoder(w).Encode(Response{Success: false, Message: "Name is required"})
            return
        }

        // Create item with ID
        created := map[string]interface{}{
            "id":    1,
            "name":  item.Name,
            "value": item.Value,
        }

        w.Header().Set("Content-Type", "application/json")
        w.WriteHeader(http.StatusCreated)
        json.NewEncoder(w).Encode(Response{
            Success: true,
            Message: "Item created",
            Data:    created,
        })
    })

    fmt.Println("Server starting on :8080")
    http.ListenAndServe(":8080", nil)
}
